// Extract Jira issue data from webhook payload
const body = $json.body || $json;
const issue = body.issue || {};
const fields = issue.fields || {};

const issueKey = issue.key || body.issueKey || 'UNKNOWN';
const summary = fields.summary || body.summary || 'No summary';
const description = fields.description || body.description || 'No description provided';
const issueType = fields.issuetype?.name || body.issueType || 'Unknown';
const priority = fields.priority?.name || body.priority || 'None';
const status = fields.status?.name || body.status || 'Unknown';
const assignee = fields.assignee?.displayName || body.assignee || 'Unassigned';
const reporter = fields.reporter?.displayName || body.reporter || 'Unknown';
const labels = (fields.labels || body.labels || []).join(', ') || 'None';
const components = (fields.components || []).map(c => c.name).join(', ') || 'None';

// Extract comments if available
const comments = (fields.comment?.comments || body.comments || [])
  .slice(-5) // Last 5 comments
  .map(c => `[${c.author?.displayName || 'Unknown'}]: ${(c.body || '').substring(0, 300)}`)
  .join('\n');

const eventType = body.webhookEvent || body.eventType || 'issue_updated';

// Build the issue text for summarisation
const issueText = `Issue: ${issueKey}
Type: ${issueType}
Priority: ${priority}
Status: ${status}
Assignee: ${assignee}
Reporter: ${reporter}
Labels: ${labels}
Components: ${components}

Summary: ${summary}

Description:
${typeof description === 'string' ? description.substring(0, 2000) : JSON.stringify(description).substring(0, 2000)}

${comments ? 'Recent Comments:\n' + comments : 'No comments.'}`;

return [{
  json: {
    issueKey,
    summary,
    issueType,
    priority,
    status,
    eventType,
    issueText
  }
}];

